query GetMiniProfileByRoninAddress($address: String!, $includeTotalAxies: Boolean!, $includeTotalBadges: Boolean!) {
  publicProfileWithRoninAddress(address: $address) {
    ...Profile
    settings {
      ...ProfileSettings
      __typename
    }
    __typename
  }
  axies(owner: $address, criteria: {stages: [4]}) @include(if: $includeTotalAxies) {
    total
    __typename
  }
  badges(ownerFilter: {obtained: true, unobtained: false, owner: $address}) @include(if: $includeTotalBadges) {
    total
    __typename
  }
}

fragment ProfileSettings on UserProfileSettings {
  avatar {
    ...ProfileAvatar
    __typename
  }
  collectionShowcase {
    ...ShowcaseAsset
    __typename
  }
  hangout {
    ...ProfileHangout
    availableBackgrounds
    __typename
  }
  badges {
    ...BadgeInfo
    __typename
  }
  axieEcosystemStats {
    axieScore
    title
    __typename
  }
  __typename
}

fragment ProfileHangout on ProfileHangout {
  axies {
    ...AxieProfileSettings
    __typename
  }
  background
  __typename
}

fragment AxieProfileSettings on Axie {
  id
  genes
  class
  newGenes
  hasMysticSuit
  image
  stage
  equipment {
    ...Erc1155Metadata
    __typename
  }
  __typename
}

fragment Erc1155Metadata on Erc1155Token {
  attributes
  description
  imageUrl
  name
  tokenAddress
  tokenId
  tokenType
  __typename
}

fragment ProfileAvatar on ProfileAvatar {
  axie {
    ...AxieProfileSettings
    __typename
  }
  position
  backgroundColor
  __typename
}

fragment ShowcaseAsset on TokenAsset {
  assetType: __typename
  ... on Axie {
    ...AxieBrief
    __typename
  }
  ... on LandPlot {
    ...LandBriefV2
    __typename
  }
  ... on LandItem {
    ...ItemSettledBrief
    order {
      id
      currentPrice
      startedAt
      currentPriceUsd
      __typename
    }
    __typename
  }
}

fragment AxieBrief on Axie {
  ...RequiredAnAxieFields
  order {
    id
    currentPrice
    currentPriceUsd
    startedAt
    __typename
  }
  __typename
}

fragment RequiredAnAxieFields on Axie {
  id
  image
  chain
  name
  genes
  newGenes
  owner
  birthDate
  bodyShape
  class
  stage
  title
  breedCount
  hasMysticSuit
  pureness
  purity
  axpInfo {
    ...AxpInfo
    __typename
  }
  battleInfo {
    banned
    banUntil
    level
    __typename
  }
  parts {
    ...AxiePart
    __typename
  }
  equipment {
    ...Erc1155Metadata
    __typename
  }
  fortuneSlips {
    total
    __typename
  }
  __typename
}

fragment AxiePart on AxiePart {
  id
  name
  class
  type
  specialGenes
  stage
  __typename
}

fragment AxpInfo on AxpInfo {
  level
  nextOnchainLevel
  onchainLevel
  shouldAscend
  xp
  xpToLevelUp
  xpToAscend
  __typename
}

fragment LandBriefV2 on LandPlot {
  tokenId
  owner
  landType
  row
  col
  order {
    id
    currentPrice
    startedAt
    currentPriceUsd
    maker
    hash
    __typename
  }
  ownerProfile {
    name
    __typename
  }
  delegation {
    ...DelegationInfo
    __typename
  }
  __typename
}

fragment DelegationInfo on Delegation {
  owner
  ownerProfile {
    ...Profile
    __typename
  }
  assignee
  assigneeProfile {
    ...Profile
    __typename
  }
  assignedAt
  expiredAt
  __typename
}

fragment Profile on PublicProfile {
  accountId
  name
  addresses {
    ...Addresses
    __typename
  }
  __typename
}

fragment Addresses on NetAddresses {
  ethereum
  ronin
  __typename
}

fragment ItemSettledBrief on LandItem {
  itemId
  name
  itemAlias
  landType
  tokenType
  tokenId
  figureURL
  rarity
  __typename
}

fragment BadgeInfo on Badge {
  id
  name
  description
  imageUrl
  obtainedAt
  owner
  baseName
  axieScore
  category
  milestone {
    level
    value
    __typename
  }
  __typename
}
